module up_down_counter(
    input                 clk,
    input                 rst,
    input                 up_down,
    output   reg [3:0]    count
);

// Up/Down counter logic
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
        count <= 4'd0;
    end else begin
        if (up_down) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
end

endmodule
